declare const require: any;
const fs = require('node:fs');

type CsvParserOptions = {
  delimiter?: string;
};

class CsvParser {
  private delimiter: string;

  constructor(options: CsvParserOptions = {}) {
    this.delimiter = options.delimiter || ',';
  }

  parse(text: string): Record<string, string>[] {
    const lines = text.split('\n');
    const headers = lines[0].split(this.delimiter);
    return lines.slice(1).map(line => {
      const values = line.split(this.delimiter);
      const record: Record<string, string> = {};
      for (let i = 0; i < headers.length; i++) {
        record[headers[i]] = values[i];
      }
      return record;
    });
  }

  stringify(rows: Record<string, string>[]): string {
    if (rows.length === 0) return '';

    const headers = Object.keys(rows[0]);
    const headerLine = headers.join(this.delimiter);

    const lines = rows.map(row => {
      return headers.map(header => {
        const value = row[header];
        if (value.includes(this.delimiter) || value.includes('"')) {
          return `"${value.replace(/"/g, '""')}"`;
        }
        return value;
      }).join(this.delimiter);
    });

    return [headerLine, ...lines].join('\n');
  }
}

class CsvFilter {
  private rows: Record<string, string>[];

  constructor(rows: Record<string, string>[]) {
    this.rows = rows;
  }

  where(predicate: (row: Record<string, string>) => boolean): CsvFilter {
    return new CsvFilter(this.rows.filter(predicate));
  }

  select(fields: string[]): CsvFilter {
    return new CsvFilter(this.rows.map(row => {
      const selectedRow: Record<string, string> = {};
      for (const field of fields) {
        if (row.hasOwnProperty(field)) {
          selectedRow[field] = row[field];
        }
      }
      return selectedRow;
    }));
  }

  sortBy(field: string): CsvFilter {
    return new CsvFilter(this.rows.slice().sort((a, b) => {
      if (a[field] < b[field]) return -1;
      if (a[field] > b[field]) return 1;
      return 0;
    }));
  }

  count(): number {
    return this.rows.length;
  }
}
